  supplier_name = EXCLUDED.supplier_name,
  sede_id = EXCLUDED.sede_id,
  sede_name = EXCLUDED.sede_name,
  warehouse_id = EXCLUDED.warehouse_id,
  warehouse_name = EXCLUDED.warehouse_name,
  product_id = EXCLUDED.product_id,
  product_tmpl_id = EXCLUDED.product_tmpl_id,
  product_name = EXCLUDED.product_name,
  category = EXCLUDED.category,
  is_storable = EXCLUDED.is_storable,
  is_child_sku = EXCLUDED.is_child_sku,
  product_qty = EXCLUDED.product_qty,
  qty_received = EXCLUDED.qty_received,
  price_unit = EXCLUDED.price_unit,
  supplier_lead_time_decl = EXCLUDED.supplier_lead_time_decl,
  supplier_min_qty = EXCLUDED.supplier_min_qty,
  supplier_price = EXCLUDED.supplier_price,
  date_order = EXCLUDED.date_order,
  date_approve = EXCLUDED.date_approve,
  date_planned = EXCLUDED.date_planned,
  effective_date = EXCLUDED.effective_date,
  approve_dow = EXCLUDED.approve_dow,
  approve_month = EXCLUDED.approve_month,
  planned_lead_time_days = EXCLUDED.planned_lead_time_days,
  lead_time_days = EXCLUDED.lead_time_days,
  source_file = EXCLUDED.source_file,
  imported_at = NOW();

INSERT INTO public.categorias_producto (nombre)
SELECT DISTINCT TRIM(category)
FROM public.stg_ml_lead_time_dataset
WHERE category IS NOT NULL AND TRIM(category) <> ''
ON CONFLICT (nombre) DO NOTHING;

INSERT INTO public.proveedores (
  ruc, razon_social, nombre_comercial, tipo, estado, homologado,
  tiempo_entrega_promedio_dias, observaciones
)
SELECT
  'LT-SUP-' || supplier_id::TEXT AS ruc,
  MAX(supplier_name) AS razon_social,
  MAX(supplier_name) AS nombre_comercial,
  'Distribuidor'::tipo_proveedor AS tipo,
  'en_evaluacion'::estado_proveedor AS estado,
  FALSE AS homologado,
  ROUND(AVG(lead_time_days))::INTEGER AS tiempo_entrega_promedio_dias,
  'Importado desde dataset_lead_time.csv. supplier_id legado=' || supplier_id::TEXT AS observaciones
FROM public.stg_ml_lead_time_dataset
GROUP BY supplier_id
ON CONFLICT (ruc) DO UPDATE SET
  razon_social = EXCLUDED.razon_social,
  nombre_comercial = EXCLUDED.nombre_comercial,
  tiempo_entrega_promedio_dias = EXCLUDED.tiempo_entrega_promedio_dias,
  observaciones = EXCLUDED.observaciones;

INSERT INTO public.productos (
  sku_padre, nombre, descripcion, categoria_id, unidad_medida, is_storable, is_active, precio_referencia, codigo_fabricante
)
SELECT
  'LT-PROD-' || product_tmpl_id::TEXT AS sku_padre,
  COALESCE(MAX(product_name), 'Producto importado ' || product_tmpl_id::TEXT) AS nombre,
  'Importado desde dataset_lead_time.csv. product_id legado=' || COALESCE(MAX(product_id)::TEXT, 'NULL') || '; product_tmpl_id legado=' || product_tmpl_id::TEXT AS descripcion,
  cp.id AS categoria_id,
  'UND' AS unidad_medida,
  COALESCE(BOOL_OR(LOWER(COALESCE(is_storable, 'f')) IN ('t','true','1')), FALSE) AS is_storable,
  TRUE AS is_active,
  AVG(COALESCE(supplier_price, price_unit)) AS precio_referencia,
  'LT-CFAB-' || product_tmpl_id::TEXT AS codigo_fabricante
FROM public.stg_ml_lead_time_dataset s
LEFT JOIN public.categorias_producto cp ON cp.nombre = s.category
WHERE product_tmpl_id IS NOT NULL
GROUP BY product_tmpl_id, cp.id
ON CONFLICT (sku_padre) DO UPDATE SET
  nombre = EXCLUDED.nombre,
  descripcion = EXCLUDED.descripcion,
  categoria_id = EXCLUDED.categoria_id,
  is_storable = EXCLUDED.is_storable,
  precio_referencia = EXCLUDED.precio_referencia,
  codigo_fabricante = EXCLUDED.codigo_fabricante;

INSERT INTO public.catalogo_precios (
  proveedor_id, producto_id, precio_costo, moneda, vigente_desde, activo
)
SELECT
  pv.id AS proveedor_id,
  pr.id AS producto_id,
  AVG(COALESCE(s.supplier_price, s.price_unit)) AS precio_costo,
  'PEN' AS moneda,
  MIN(s.date_approve)::DATE AS vigente_desde,
  TRUE AS activo
FROM public.stg_ml_lead_time_dataset s
JOIN public.proveedores pv ON pv.ruc = 'LT-SUP-' || s.supplier_id::TEXT
JOIN public.productos pr ON pr.sku_padre = 'LT-PROD-' || s.product_tmpl_id::TEXT
WHERE s.product_tmpl_id IS NOT NULL
GROUP BY pv.id, pr.id
ON CONFLICT (proveedor_id, producto_id, vigente_desde) DO UPDATE SET
  precio_costo = EXCLUDED.precio_costo,
  activo = EXCLUDED.activo;

INSERT INTO public.ml_modelos (
  nombre, tipo, proposito, version, metricas, hiperparametros, activo
)
SELECT
  'XGBoost Lead Time v1',
  'xgboost',
  'lead_time',
  'lead-time-xgb-20260626-102543',
  '{"mae": 0.6065180180483012, "rmse": 1.3271502249960825, "r2": 0.6715522730065879}'::jsonb,
  '{"target": "lead_time_days", "dataset": "dataset_lead_time.csv", "rows_total": 1251, "rows_train": 1000, "rows_test": 251}'::jsonb,
  FALSE
WHERE NOT EXISTS (
  SELECT 1
  FROM public.ml_modelos
  WHERE tipo = 'xgboost'
    AND proposito = 'lead_time'
    AND version = 'lead-time-xgb-20260626-102543'
);

COMMIT;
